Here's a modern MSTest test class covering success, failure, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    // Helper to create a DataFetcher with a fake handler
    private static DataFetcher CreateFetcher(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
    {
        var mock = new MockHandler(handler);
        return new DataFetcher(new HttpClient(mock));
    }

    [TestMethod]
    [Timeout(5000)] // fails the test if it hangs beyond 5s
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var fetcher = CreateFetcher((req, ct) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        var result = await fetcher.FetchAsync("https://example.com",
            TestContext.CancellationTokenSource.Token);

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_OnHttpError()
    {
        var fetcher = CreateFetcher((req, ct) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.InternalServerError)));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com",
                TestContext.CancellationTokenSource.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        using var cts = CancellationTokenSource.CreateLinkedTokenSource(
            TestContext.CancellationTokenSource.Token);

        var fetcher = CreateFetcher(async (req, ct) =>
        {
            await Task.Delay(Timeout.Infinite, ct); // simulates slow server
            return new HttpResponseMessage(); // unreachable
        });

        cts.Cancel();

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    public TestContext TestContext { get; set; } = null!;

    // Minimal testable handler — no third-party mocking library needed
    private sealed class MockHandler(
        Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => handler(request, cancellationToken);
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `async Task` test methods | MSTest awaits them natively — no `GetAwaiter()` hacks |
| `[Timeout(ms)]` | Guards against hanging tests; integrates with the runner's cancellation |
| `TestContext.CancellationTokenSource.Token` | Linked to `[Timeout]` — auto-cancels the token when the timeout fires |
| `CreateLinkedTokenSource` | In the cancellation test, links your CTS to the timeout token so *either* trigger works |
| Custom `HttpMessageHandler` | Avoids mocking-library overhead; gives full control over the HTTP pipeline |

The `TestContext.CancellationTokenSource` property (MSTest 3.x+) is the modern replacement for manually wiring cancellation — it fires automatically when `[Timeout]` expires, so your code under test gets a clean cooperative cancellation signal instead of a hard thread abort.
